  @Override
  public ResolvedCdsTranche resolve(ReferenceData refData) {
    ResolvedCdsIndex resolvedIndex = underlyingIndex.resolve(refData);
    List<SchedulePeriod> schedulePeriods = paymentSchedule.createSchedule(refData).getPeriods();
    ImmutableList.Builder<CreditCouponPaymentPeriod> periods = ImmutableList.builder();

    for (SchedulePeriod schedulePeriod : schedulePeriods) {
      CreditCouponPaymentPeriod period = CreditCouponPaymentPeriod.builder()
          .startDate(schedulePeriod.getStartDate())
          .endDate(schedulePeriod.getEndDate())
          .unadjustedStartDate(schedulePeriod.getUnadjustedStartDate())
          .unadjustedEndDate(schedulePeriod.getUnadjustedEndDate())
          .effectiveStartDate(calculateEffectiveStartDate(schedulePeriod.getStartDate(), refData))
          .notional(notional)
          .fixedRate(fixedRate)
          .yearFraction(dayCount.yearFraction(schedulePeriod.getStartDate(), schedulePeriod.getEndDate()))
          .currency(currency)
          .paymentDate(paymentSchedule.getPaymentDateOffset().adjust(schedulePeriod.getEndDate(), refData))
          .build();
      periods.add(period);
    }

    return ResolvedCdsTranche.builder()
        .buySell(buySell)
        .attachmentPoint(attachmentPoint)
        .detachmentPoint(detachmentPoint)
        .underlyingIndex(resolvedIndex)
        .paymentPeriods(periods.build())
        .protectionEndDate(paymentSchedule.getEndDate())
        .dayCount(dayCount)
        .paymentOnDefault(paymentOnDefault)
        .protectionStart(protectionStart)
        .stepinDateOffset(stepinDateOffset)
        .settlementDateOffset(settlementDateOffset)
        .build();
  }

  private LocalDate calculateEffectiveStartDate(LocalDate startDate, ReferenceData refData) {
    return protectionStart.isBeginning() ? startDate.minusDays(1) : startDate;
