/**
 * A CDS tranche product representing a slice of credit risk from a CDS index portfolio.
 * <p>
 * A CDS tranche is defined by attachment and detachment points that determine the subordination level.
 * The tranche buyer/seller receives/pays protection only for losses between the attachment and detachment points.
 */
@BeanDefinition
public final class CdsTranche
    implements Product, Resolvable<ResolvedCdsTranche>, ImmutableBean, Serializable {

  /**
   * Whether the CDS tranche is buy or sell.
   * <p>
   * A value of 'Buy' implies buying protection, where the fixed coupon is paid
   * and the protection is received in the event of default.
   * A value of 'Sell' implies selling protection, where the fixed coupon is received
   * and the protection is paid in the event of default.
   */
  @PropertyDefinition(validate = "notNull")
  private final BuySell buySell;
  /**
   * The underlying CDS index.
   * <p>
   * This index product defines the reference portfolio for the tranche.
   */
  @PropertyDefinition(validate = "notNull")
  private final CdsIndex underlyingIndex;
  /**
   * The attachment point.
   * <p>
   * This is the lower bound of the loss interval as a proportion (0.0 to 1.0).
   * Losses below this point are absorbed by more junior tranches.
   */
  @PropertyDefinition(validate = "ArgChecker.notNegative")
  private final double attachmentPoint;
  /**
   * The detachment point.
   * <p>
   * This is the upper bound of the loss interval as a proportion (0.0 to 1.0).
   * Losses above this point are absorbed by more senior tranches.
   */
  @PropertyDefinition(validate = "ArgChecker.notNegative")
  private final double detachmentPoint;
