package com.opengamma.strata.pricer.credit;

import java.time.LocalDate;

import com.opengamma.strata.basics.currency.CurrencyAmount;
import com.opengamma.strata.collect.ArgChecker;
import com.opengamma.strata.pricer.common.PriceType;
import com.opengamma.strata.product.credit.ResolvedCdsTranche;

/**
 * Pricer for CDS tranche products based on ISDA standard model.
 * <p>
 * A CDS tranche product prices the protection for losses between the attachment and detachment points.
 * The present value is calculated by computing the expected loss between these points
 * and discounting back to the valuation date.
 */
public class IsdaCdsTranchePricer {

  /**
   * Default implementation using the ORIGINAL ISDA accrual-on-default formula.
   */
  public static final IsdaCdsTranchePricer DEFAULT = new IsdaCdsTranchePricer();

  /**
   * The underlying CDS index pricer.
   */
  private final IsdaHomogenousCdsIndexProductPricer indexPricer;

  /**
   * Constructor using default CDS index pricer.
   */
  public IsdaCdsTranchePricer() {
    this.indexPricer = IsdaHomogenousCdsIndexProductPricer.DEFAULT;
  }

  /**
   * Constructor with explicit index pricer.
   *
   * @param indexPricer  the index pricer, not null
   */
  public IsdaCdsTranchePricer(IsdaHomogenousCdsIndexProductPricer indexPricer) {
    this.indexPricer = ArgChecker.notNull(indexPricer, "indexPricer");
  }

  //-------------------------------------------------------------------------
  /**
   * Calculates the present value of the CDS tranche.
   * <p>
   * The present value is calculated as the discounted expected loss within the tranche's attachment
   * and detachment points. The calculation assumes a homogeneous portfolio approximation.
   *
   * @param tranche  the resolved CDS tranche product
   * @param ratesProvider  the rates and credit curves provider
   * @param referenceDate  the reference date
   * @param priceType  the price type (clean or dirty)
   * @return the present value
   */
  public CurrencyAmount presentValue(
      ResolvedCdsTranche tranche,
      CreditRatesProvider ratesProvider,
      LocalDate referenceDate,
      PriceType priceType) {

    // Price the underlying index
    CurrencyAmount indexPv = indexPricer.presentValue(
        tranche.getUnderlyingIndex(),
        ratesProvider,
        referenceDate,
        priceType);

    // Apply tranche scaling based on attachment and detachment points
    double trancheNotional = tranche.getNotional();
    double attachmentPoint = tranche.getAttachmentPoint();
    double detachmentPoint = tranche.getDetachmentPoint();

    // The tranche PV is the index PV scaled by the tranche loss interval
