package com.opengamma.strata.measure.credit;

import com.opengamma.strata.basics.ReferenceData;
import com.opengamma.strata.basics.currency.CurrencyAmount;
import com.opengamma.strata.data.scenario.ScenarioMarketData;
import com.opengamma.strata.pricer.credit.IsdaCdsTranchePricer;
import com.opengamma.strata.pricer.credit.CreditRatesProvider;
import com.opengamma.strata.pricer.common.PriceType;
import com.opengamma.strata.product.credit.CdsTrancheTrade;
import com.opengamma.strata.product.credit.ResolvedCdsTrancheTrade;

/**
 * Measure calculations for CDS tranche trades.
 * <p>
 * Provides pricing and risk measure calculations for CDS tranches.
 */
public class CdsTrancheMeasureCalculations {

  /**
   * Default implementation using the ISDA pricer.
   */
  public static final CdsTrancheMeasureCalculations DEFAULT = new CdsTrancheMeasureCalculations(
      IsdaCdsTranchePricer.DEFAULT);

  /**
   * The pricer for CDS tranches.
   */
  private final IsdaCdsTranchePricer pricer;

  /**
   * Creates an instance with the specified pricer.
   *
   * @param pricer  the CDS tranche pricer, not null
   */
  public CdsTrancheMeasureCalculations(IsdaCdsTranchePricer pricer) {
    this.pricer = pricer;
  }

  //-------------------------------------------------------------------------
  /**
   * Calculates present value for each scenario.
   *
   * @param trade  the trade
   * @param marketData  the market data
   * @param refData  the reference data
   * @return the present value
   */
  public CurrencyAmount presentValue(
      CdsTrancheTrade trade,
      ScenarioMarketData marketData,
      ReferenceData refData) {

    ResolvedCdsTrancheTrade resolved = trade.resolve(refData);
    CreditRatesProvider ratesProvider = marketData.scenario(0)
        .data(CreditRatesMarketDataLookup.INSTANCE)
        .ratesProvider();

    return pricer.presentValue(
        resolved.getProduct(),
        ratesProvider,
        trade.getInfo().getSettlementDate().orElse(refData.getReferenceDate()),
        PriceType.DIRTY);
  }

  /**
   * Calculates unit price for each scenario.
   *
   * @param trade  the trade
   * @param marketData  the market data
   * @param refData  the reference data
   * @return the unit price
   */
  public double unitPrice(
      CdsTrancheTrade trade,
      ScenarioMarketData marketData,
      ReferenceData refData) {

    ResolvedCdsTrancheTrade resolved = trade.resolve(refData);
    CreditRatesProvider ratesProvider = marketData.scenario(0)
        .data(CreditRatesMarketDataLookup.INSTANCE)
        .ratesProvider();

    return pricer.price(
        resolved.getProduct(),
        ratesProvider,
        trade.getInfo().getSettlementDate().orElse(refData.getReferenceDate()),
        PriceType.CLEAN);
  }

}

